import { Component, inject, OnInit, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { DocumentService, Doc } from '../../core/document';

const UPLOAD_PHASES = [
  { label: 'Verificando formato...', icon: 'bi-file-earmark-check', duration: 1500 },
  { label: 'Validando contenido e idioma...', icon: 'bi-translate', duration: 2500 },
  { label: 'Subiendo a la nube...', icon: 'bi-cloud-upload', duration: 99999 },
];

@Component({
  selector: 'app-dashboard',
  imports: [CommonModule, FormsModule],
  styles: ``,
  templateUrl: './dashboard.html',
})
export class Dashboard implements OnInit, OnDestroy {
  private svc = inject(DocumentService);
  private pollTimer: ReturnType<typeof setInterval> | null = null;
  private phaseTimer: ReturnType<typeof setTimeout> | null = null;

  docs: Doc[] = [];
  selected = new Set<number>();
  loading = false;
  error = '';
  citations: string[] = [];
  showCitations = false;

  uploading = false;
  uploadPhaseIndex = 0;

  get uploadPhase() { return UPLOAD_PHASES[this.uploadPhaseIndex]; }

  ngOnInit() { this.load(); }

  ngOnDestroy() {
    this.stopPolling();
    if (this.phaseTimer) clearTimeout(this.phaseTimer);
  }

  load() {
    this.loading = true;
    this.svc.list().subscribe({
      next: docs => {
        this.docs = docs;
        this.loading = false;
        this.managePoll();
      },
      error: () => { this.error = 'Error al cargar documentos.'; this.loading = false; },
    });
  }

  private hasPending() {
    return this.docs.some(d => d.status === 'pending' || d.status === 'processing');
  }

  private managePoll() {
    if (this.hasPending()) {
      this.startPolling();
    } else {
      this.stopPolling();
    }
  }

  private startPolling() {
    if (this.pollTimer) return;
    this.pollTimer = setInterval(() => {
      this.svc.list().subscribe(docs => {
        this.docs = docs;
        if (!this.hasPending()) this.stopPolling();
      });
    }, 3000);
  }

  private stopPolling() {
    if (this.pollTimer) { clearInterval(this.pollTimer); this.pollTimer = null; }
  }

  private advancePhase(index: number) {
    if (index >= UPLOAD_PHASES.length - 1) return;
    this.phaseTimer = setTimeout(() => {
      this.uploadPhaseIndex = index + 1;
      this.advancePhase(index + 1);
    }, UPLOAD_PHASES[index].duration);
  }

  toggle(id: number) {
    this.selected.has(id) ? this.selected.delete(id) : this.selected.add(id);
  }

  toggleAll() {
    if (this.selected.size === this.docs.length) this.selected.clear();
    else this.docs.forEach(d => this.selected.add(d.id));
  }

  onFileChange(event: Event) {
    const input = event.target as HTMLInputElement;
    const file = input.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      this.error = 'Solo se aceptan archivos PDF (.pdf).';
      input.value = '';
      return;
    }

    this.uploading = true;
    this.uploadPhaseIndex = 0;
    this.error = '';
    this.advancePhase(0);

    this.svc.upload(file).subscribe({
      next: () => {
        this.finishUpload(input);
        this.load();
      },
      error: (e) => {
        this.error = e.error?.detail ?? 'Error al subir el archivo.';
        this.finishUpload(input);
      },
    });
  }

  private finishUpload(input: HTMLInputElement) {
    if (this.phaseTimer) { clearTimeout(this.phaseTimer); this.phaseTimer = null; }
    this.uploading = false;
    this.uploadPhaseIndex = 0;
    input.value = '';
  }

  download(doc: Doc) {
    this.svc.download(doc.id).subscribe(res => {
      const url = URL.createObjectURL(res.body!);
      const a = document.createElement('a');
      a.href = url; a.download = doc.filename; a.click();
      URL.revokeObjectURL(url);
    });
  }

  deleteOne(id: number) {
    if (!confirm('¿Eliminar este documento?')) return;
    this.svc.delete(id).subscribe(() => { this.selected.delete(id); this.load(); });
  }

  deleteSelected() {
    if (!this.selected.size) return;
    if (!confirm(`¿Eliminar ${this.selected.size} documento(s)?`)) return;
    this.svc.deleteBatch([...this.selected]).subscribe(() => { this.selected.clear(); this.load(); });
  }

  generateApa7() {
    const ids = this.selected.size ? [...this.selected] : this.docs.map(d => d.id);
    this.svc.apa7(ids).subscribe(res => { this.citations = res.citations; this.showCitations = true; });
  }

  copyCitations() {
    navigator.clipboard.writeText(this.citations.join('\n\n'));
  }
}
