import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';

const API = '/api';

export interface Category {
  category: string;
  score: number;
}

export interface Doc {
  id: number;
  filename: string;
  uploaded_at: string;
  status: 'pending' | 'processing' | 'done' | 'error';
  title: string | null;
  authors: string | null;
  year: number | null;
  journal: string | null;
  categories: Category[];
}

@Injectable({ providedIn: 'root' })
export class DocumentService {
  private http = inject(HttpClient);

  list() {
    return this.http.get<Doc[]>(`${API}/documents`);
  }

  upload(file: File) {
    const form = new FormData();
    form.append('file', file);
    return this.http.post<{ id: number; filename: string; object_key: string }>(
      `${API}/documents`, form
    );
  }

  download(id: number) {
    return this.http.get(`${API}/documents/${id}/download`, {
      responseType: 'blob',
      observe: 'response',
    });
  }

  delete(id: number) {
    return this.http.delete(`${API}/documents/${id}`);
  }

  deleteBatch(ids: number[]) {
    return this.http.post(`${API}/documents/delete-batch`, { document_ids: ids });
  }

  apa7(ids: number[]) {
    return this.http.post<{ citations: string[] }>(`${API}/documents/apa7`, { document_ids: ids });
  }
}
